import{_ as a,o as t,c as r,a5 as o}from"./chunks/framework.B5tqjWbr.js";const m=JSON.parse('{"title":"学习记录 #0003：PWM调制技术——从SPWM到SVPWM","description":"","frontmatter":{"date":"2026-06-14T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"学习记录 #0003：PWM调制技术——从SPWM到SVPWM","tags":["power-electronics"],"status":"learning","summary":"**日期**：2026-06-13 **课程**：第3课 — PWM调制技术——从SPWM到SVPWM **状态**：进行中"},"headers":[],"relativePath":"content/power/archive/old-learning-records/0003-pwm-techniques-spwm-svpwm.md","filePath":"content/power/archive/old-learning-records/0003-pwm-techniques-spwm-svpwm.md","lastUpdated":null}'),i={name:"content/power/archive/old-learning-records/0003-pwm-techniques-spwm-svpwm.md"};function l(s,e,n,c,p,P){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="学习记录-0003-pwm调制技术——从spwm到svpwm" tabindex="-1">学习记录 #0003：PWM调制技术——从SPWM到SVPWM <a class="header-anchor" href="#学习记录-0003-pwm调制技术——从spwm到svpwm" aria-label="Permalink to &quot;学习记录 #0003：PWM调制技术——从SPWM到SVPWM&quot;">​</a></h1><p><strong>日期</strong>：2026-06-13 <strong>课程</strong>：第3课 — PWM调制技术——从SPWM到SVPWM <strong>状态</strong>：进行中</p><h2 id="关键洞察" tabindex="-1">关键洞察 <a class="header-anchor" href="#关键洞察" aria-label="Permalink to &quot;关键洞察&quot;">​</a></h2><ol><li><strong>SPWM核心</strong>：面积等效原理——脉冲宽度按正弦规律变化，使输出电压平均值逼近正弦波</li><li><strong>单极性 vs 双极性</strong>：单极性谐波在2fc处（等效倍频），电压跳变减半，THD更低；双极性实现简单</li><li><strong>SVPWM本质</strong>：用8个离散电压矢量（6非零+2零），通过伏秒平衡合成任意参考矢量</li><li><strong>Min-Max法</strong>：Voffset = -(max+min)/2，等价于三次谐波注入，无需扇区判断，代码简洁</li><li><strong>15%提升来源</strong>：SPWM最大V1_peak = Vdc/2，SVPWM最大V1_peak = Vdc/√3，比值2/√3 ≈ 1.1547</li></ol><h2 id="代码要点" tabindex="-1">代码要点 <a class="header-anchor" href="#代码要点" aria-label="Permalink to &quot;代码要点&quot;">​</a></h2><ul><li>SPWM实现：正弦查表法 + 规则采样 + 定时器中断更新CMPA</li><li>SVPWM实现：Min-Max法（逆Clark → 计算offset → 注入 → 写CCR）</li><li>三相正弦表：A/B/C相索引偏移85/171（256点表）</li></ul><h2 id="待深入问题" tabindex="-1">待深入问题 <a class="header-anchor" href="#待深入问题" aria-label="Permalink to &quot;待深入问题&quot;">​</a></h2><ul><li>[ ] 三电平SVPWM的扇区判断与两电平有何不同？</li><li>[ ] 过调制区域（m_a &gt; 1）的SVPWM怎么处理？</li><li>[ ] 中心对齐PWM与边沿对齐PWM对电流采样的影响？</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>进入第4课：数字控制基础——从连续到离散</p>',10)])])}const h=a(i,[["render",l]]);export{m as __pageData,h as default};
